 local function ReCalculateBonus(self, ...) local retVal = self.dycOldReCalculateBonus(self, ...) local bonus = self.totalbonus or 0x1 self.inst:DoTaskInTime(FRAMES * 0x3, function() bonus = bonus + self.inst:GetCharacterBonus( "vision" ) GetWorld().minimap.MiniMap:SetRevealRadiusMultiplier(bonus) end) return retVal end local function DYCFarseer(self) self.dycOldReCalculateBonus = self.ReCalculateBonus self.ReCalculateBonus = ReCalculateBonus end return DYCFarseer 